# er_classification_plots.R
#
# This script reads the summary metrics CSV file generated by the Python script
# and creates a grouped bar chart for each adjustment method to visualize
# model performance, including error bars for standard deviation (SD) and
# standard error of the mean (SEM).

# Install necessary packages if they are not already installed
if (!require(ggplot2)) install.packages("ggplot2")
if (!require(readr)) install.packages("readr")
if (!require(dplyr)) install.packages("dplyr")
if (!require(stringr)) install.packages("stringr")

# Load libraries
library(ggplot2)
library(readr)
library(dplyr)
library(stringr)
library(forcats)

# --- Configuration ---
# Define file paths and names for better organization.
CSV_FILE <- "outputs/metrics/hist_gradient_er_summary.csv"
FIG_DIR <- "outputs/figures/paired_er"
FILENAME_BASE <- "er_model_comparison"

# Define the adjustment methods to plot.
# This list can be updated as more methods are added.
ADJUSTMENT_METHODS <- c("Unadjusted", "NPN Global", "MNN", "Min-Mean", "Weird-Mean", "GMM", "GMM Scale Separate", "GMM NPN", "Simple", "Combat")
# --- End Configuration ---


# Create the plot directory if it doesn't exist
dir.create(FIG_DIR, showWarnings = FALSE)

# Read the full dataset
# Add a tryCatch block for robust error handling if the file is missing.
metrics_df <- tryCatch({
  read_csv(CSV_FILE, show_col_types = FALSE)
}, error = function(e) {
  message(paste("Error reading file:", CSV_FILE))
  message("Please ensure the summary CSV has been generated by the Python script.")
  return(NULL)
})

# Stop execution if the data file could not be read.
if (is.null(metrics_df)) {
  stop("Aborting script due to missing or invalid input file.", call. = FALSE)
}

# Example:
# adjuster,evaluation,metric,mean,std,sem
# Combat,Combined,Accuracy,0.9367,0.0112,0.0006

# --- Loop through each adjustment method and generate a plot ---
for (adj_method in ADJUSTMENT_METHODS) {
  # Make a copy of the unadjusted rows, mutating the evaluation column to include the adjustment method, 
  # and changing the adjustment method to the current method
  unadjusted_rows <- metrics_df %>%
    filter(adjuster == "Unadjusted") %>%
    mutate(evaluation = paste(evaluation, "(Unadj)")) %>%
    mutate(adjuster = adj_method)
  
  # Filter the data for the current adjustment method
  method_df <- metrics_df %>%
    filter(adjuster == adj_method)
  
  if (adj_method != "Unadjusted") {
    # If the adjustment method is not "Unadjusted", add the unadjusted rows to the method_df
    method_df <- bind_rows(method_df, unadjusted_rows)
  }
  
  # Check if there is any data for the current method before proceeding
  if (nrow(method_df) == 0) {
    message(paste("Warning: No data found for adjustment method '", adj_method, "'. Skipping plot generation.", sep = ""))
    next # Skip to the next iteration of the loop
  }
  
  # Prepare the data for plotting by converting columns to factors.
  # This ensures a logical order in the plot legend and axes.
  method_df <- method_df %>%
    mutate(
      evaluation = factor(evaluation, levels = c(
        "gse62944",
        "gse62944 (Unadj)",
        "Combined on gse62944",
        "Combined on gse62944 (Unadj)",
        "Train on gse20194, Test on gse62944",
        # "Train on gse20194, Test on gse62944 (Unadj)",
        "Train on gse62944, Test on gse20194",
        # "Train on gse62944, Test on gse20194 (Unadj)",
        "gse20194",
        "gse20194 (Unadj)",
        "Combined on gse20194",
        "Combined on gse20194 (Unadj)",
        "Combined",
        "Combined (Unadj)"
      )),
      metric = factor(metric, levels = c("Accuracy", "ROC AUC", "Sensitivity (TPR)", "Specificity (TNR)", "MCC (Matthews Corr Coef)")),
      evaluation = forcats::fct_recode(evaluation, 
        "Comb. 62944" = "Combined on gse62944", 
        "Comb. 62944 (Unadj)" = "Combined on gse62944 (Unadj)", 
        "Tr. 20194 Te. 62944" = "Train on gse20194, Test on gse62944", 
        "Tr. 62944 Te. 20194" = "Train on gse62944, Test on gse20194",
        "Comb. 20194" = "Combined on gse20194", 
        "Comb. 20194 (Unadj)" = "Combined on gse20194 (Unadj)",
        "Comb." = "Combined", 
        "Comb. (Unadj)" = "Combined (Unadj)",
        # "Tr. 20194 Te. 62944 (Unadj)" = "Train on gse62944, Test on gse20194 (Unadj)",
        # "Tr. 62944 Te. 20194 (Unadj)" = "Train on gse20194, Test on gse62944 (Unadj)"
      )
    ) %>%
    # Remove any rows with metrics that are not in the defined factor levels
    filter(!is.na(metric)) %>%
    filter(!is.na(evaluation))

  # --- Create the Plot ---
  metrics_plot <- ggplot(method_df, aes(x = metric, y = mean, fill = evaluation)) +
    # Add bars for the mean score
    geom_bar(stat = "identity", position = position_dodge(width = 0.9), alpha = 0.8) +
    
    # Add wider, lighter error bars for the standard deviation (SD)
    geom_errorbar(
      aes(ymin = mean - std, ymax = mean + std),
      width = 0.3,
      position = position_dodge(width = 0.9),
      color = "gray50",
      linewidth = 0.5
    ) +
    
    # Add narrower, darker error bars for the standard error of the mean (SEM)
    geom_errorbar(
      aes(ymin = mean - sem, ymax = mean + sem),
      width = 0.15,
      position = position_dodge(width = 0.9),
      color = "black",
      linewidth = 1.0 # Make SEM bars thicker to stand out
    ) +
    
    # Set plot labels and title, making it dynamic based on the adjustment method
    labs(
      title = paste("HistGradientBoosting Performance on ER Status Prediction (", adj_method, ")", sep = ""),
      subtitle = "Comparing Models Trained on Individual vs. Combined Datasets",
      x = "Performance Metric",
      y = "Mean Score",
      fill = "Evaluation Scenario"
    ) +
    
    # Use a clean theme
    theme_minimal(base_size = 14) +
    
    # Customize theme elements
    theme(
      legend.position = "bottom",
      plot.title = element_text(hjust = 0.5, face = "bold"),
      plot.subtitle = element_text(hjust = 0.5),
      axis.text.x = element_text(angle = 0, vjust = 0.5)
    ) +
    
    # Adjust y-axis to focus on the area of interest
    coord_cartesian(ylim = c(0.0, 1.00)) +
    
    # Use a color-blind friendly palette
    scale_fill_brewer(palette = "Paired")

  # --- Save the plot as a PDF ---
  # Construct a unique filename for each adjustment method's plot
  filename_for_plot <- paste0(FILENAME_BASE, "_", str_to_lower(adj_method), ".pdf")
  plot_file_path <- file.path(FIG_DIR, filename_for_plot)
  
  ggsave(
    plot_file_path,
    plot = metrics_plot,
    device = "pdf",
    width = 11,
    height = 8.5,
    units = "in"
  )
  
  # Print a confirmation message for each file created
  cat("Plot saved to:", plot_file_path, "\n")
}

